1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array for empty grid", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should return empty array for single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should return empty array for two live cells (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block of four cells alive (still life)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    expect(nextGeneration(block)).toEqual([[0, 0], [1, 0], [0, 1], [1, 1]]);
17	  });
18	  it.todo("should bring a dead cell to life with exactly 3 live neighbors (reproduction)");
19	  it.todo("should kill a live cell with more than 3 live neighbors (overpopulation)");
20	  it.todo("should transform a blinker to its next generation (oscillator)");
21	});
