1	export type Cell = [row: number, col: number];
2	
3	const cellKey = (cell: Cell): string => `${cell[0]},${cell[1]}`;
4	
5	const neighbors = (cell: Cell): Cell[] => {
6	  const [r, c] = cell;
7	  return [
8	    [r - 1, c - 1], [r - 1, c], [r - 1, c + 1],
9	    [r,     c - 1],             [r,     c + 1],
10	    [r + 1, c - 1], [r + 1, c], [r + 1, c + 1],
11	  ] as Cell[];
12	};
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const liveSet = new Set(cells.map(cellKey));
16	  const neighborCount = new Map<string, number>();
17	
18	  for (const cell of cells) {
19	    for (const n of neighbors(cell)) {
20	      const k = cellKey(n);
21	      neighborCount.set(k, (neighborCount.get(k) ?? 0) + 1);
22	    }
23	  }
24	
25	  const result: Cell[] = [];
26	  for (const [k, count] of neighborCount) {
27	    const [r, c] = k.split(",").map(Number);
28	    const cell: Cell = [r, c];
29	    if (count === 3 || (count === 2 && liveSet.has(k))) {
30	      result.push(cell);
31	    }
32	  }
33	
34	  result.sort((a, b) => a[1] - b[1] || a[0] - b[0]);
35	  return result;
36	}
